import os
import subprocess
import shutil

def backup_directory(dir_path, format):
    if not os.path.exists(dir_path):
        print(f"Error: Directory '{dir_path}' does not exist.")
        return
    
    if not os.path.isdir(dir_path):
        print(f"Error: '{dir_path}' is not a directory.")
        return

    filename = dir_path.split("/")[-1]
    output_filename = f"{filename}.{format}"
    
    if format == '7z':
        command = f"7za a -t7z {output_filename} {dir_path}"
    elif format == 'tar.gz':
        command = f"tar czf {output_filename} {dir_path}"
    elif format == 'tar.bz2':
        command = f"tar jcf {output_filename} {dir_path}"
    elif format == 'zip':
        command = f"zip -r {output_filename} {dir_path}"
    
    print(f"Creating backup in {format} format: {command}")
    
    try:
        subprocess.run(command, shell=True, check=True)
        print(f"Backup created successfully: {output_filename}")
    except Exception as e:
        print(f"Error creating backup: {e}")

if __name__ == "__main__":
    dir_path = input("Enter the directory path to back up: ")
    format = input("Enter the desired compression format (7z, tar.gz, tar.bz2, zip): ")
    
    backup_directory(dir_path, format)